 78→async function isForkFeatureEnabled(): Promise<boolean> {
 79→  try {
 80→    const result = await chrome.storage?.sync?.get({ [StorageKeys.FORK_ENABLED]: false });
 81→    return isForkFeatureEnabledValue(result?.[StorageKeys.FORK_ENABLED]);
 82→  } catch {
