125→/**
126→ * Initialize all features sequentially to reduce simultaneous load
127→ */
128→async function initializeFeatures(): Promise<void> {
129→  if (initialized) return;
130→  initialized = true;
131→
132→  try {
133→    if (!hasValidExtensionContext()) {
134→      return;
135→    }
136→    // Sequential initialization with small delays between features
137→    // to further reduce simultaneous resource usage
138→    const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
139→
140→    // Check if this is a custom website (only prompt manager should be enabled)
141→    const isCustomSite = await isCustomWebsite();
142→
143→    if (isCustomSite) {
144→      // Only start prompt manager for custom websites
145→      console.log('[Gemini Voyager] Custom website detected, starting Prompt Manager only');
146→
147→      promptManagerInstance = await startPromptManager();
148→      return;
149→    }
150→
151→    console.log('[Gemini Voyager] Not a custom website, checking for Gemini/AI Studio');
152→
153→    const isEnterprise = isGeminiEnterpriseEnvironment(
154→      {
155→        hostname: location.hostname,
156→        pathname: location.pathname,
157→        search: location.search,
158→        hash: location.hash,
159→      },
160→      document,
161→    );
162→
163→    if (isEnterprise) {
164→      console.log('[Gemini Voyager] Gemini Enterprise detected, starting Prompt Manager only');
