 1→/**
 2→ * Selection/Cursor Helpers
 3→ *
 4→ * Provides utilities to get/set cursor position based on pure text offset via TreeWalker.
 5→ * This is robust against DOM re-renders as long as the text content remains consistent.
 6→ */
 7→
 8→/**
 9→ * Get the current cursor position as a global text offset relative to the root element.
10→ */
11→export function getTextOffset(root: HTMLElement): number | null {
12→  const selection = window.getSelection();
13→  if (!selection || selection.rangeCount === 0) return null;
14→
15→  const range = selection.getRangeAt(0);
16→
17→  // Create a range that spans from the start of the root to the cursor
18→  const preCaretRange = range.cloneRange();
19→  preCaretRange.selectNodeContents(root);
20→  preCaretRange.setEnd(range.endContainer, range.endOffset);
21→
22→  // The length of the string in that range is our offset
23→  return preCaretRange.toString().length;
24→}
25→
26→/**
27→ * Restore the cursor to a specific global text offset.
28→ */
29→export function setCaretPosition(root: HTMLElement, targetOffset: number): void {
30→  const selection = window.getSelection();
31→  if (!selection) return;
32→
33→  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, null);
34→  let currentOffset = 0;
35→  let found = false;
36→
37→  while (walker.nextNode()) {
38→    const node = walker.currentNode;
39→    const length = node.textContent?.length || 0;
40→
41→    if (currentOffset + length >= targetOffset) {
42→      // The target is inside this node
43→      const range = document.createRange();
44→      const relativeOffset = targetOffset - currentOffset;
45→
46→      range.setStart(node, relativeOffset);
47→      range.collapse(true);
48→
49→      selection.removeAllRanges();
50→      selection.addRange(range);
51→      found = true;
52→      break;
53→    }
54→
55→    currentOffset += length;
56→  }
57→
58→  // Fallback: If targetOffset is beyond content length, set to end
59→  if (!found) {
60→    const range = document.createRange();
61→    range.selectNodeContents(root);
62→    range.collapse(false);
63→    selection.removeAllRanges();
64→    selection.addRange(range);
65→  }
66→}
