211→// ============================================================================
212→// Event Handlers
213→// ============================================================================
214→
215→/**
216→ * Handle keydown events on the input area
217→ */
218→function handleKeyDown(event: KeyboardEvent): void {
219→  // Early exit if feature is disabled (should not happen, but defensive check)
220→  if (!isEnabled) return;
221→
222→  // Fix for Issue 260: Ignore events during IME composition
223→  if (event.isComposing) return;
224→
225→  // Only handle Enter key
226→  if (event.key !== 'Enter') return;
227→
228→  const target = event.target as HTMLElement;
229→
230→  // Check if we're in an editable area (Gemini uses contenteditable divs)
231→  const isContentEditable =
232→    target.isContentEditable || target.getAttribute('contenteditable') === 'true';
233→  const isTextarea = target.tagName === 'TEXTAREA';
234→
235→  // Ignore INPUT elements - they are usually single-line (search, rename)
236→  // and pressing Enter there should trigger the default submit action
237→  if (!isContentEditable && !isTextarea) return;
238→
239→  // Ctrl+Enter or Cmd+Enter: Send the message
240→  if (event.ctrlKey || event.metaKey) {
241→    // Pass the current input target context so we only find its corresponding send button
242→    const sendButton = findSendButton(target);
243→    if (sendButton) {
244→      event.preventDefault();
245→      event.stopPropagation();
246→      sendButton.click();
247→    }
248→    return;
249→  }
250→
251→  // Shift+Enter: Default behavior (already inserts newline in most cases)
252→  if (event.shiftKey) return;
253→
254→  // Plain Enter: Insert a newline instead of sending
255→  event.preventDefault();
256→  event.stopPropagation();
257→
258→  if (isContentEditable) {
259→    insertNewlineInContentEditable(target);
260→  } else if (isTextarea) {
261→    insertNewlineInTextarea(target as HTMLTextAreaElement);
262→  }
263→}
