265→// ============================================================================
266→// Attachment Logic
267→// ============================================================================
268→
269→/**
270→ * Attach event listener to an input element
271→ */
272→function attachToInput(element: HTMLElement): void {
273→  // Prevent duplicate listeners
274→  if (attachedElements.has(element)) return;
275→
276→  // Use capture phase to intercept before other handlers
277→  element.addEventListener('keydown', handleKeyDown, { capture: true });
278→
279→  attachedElements.add(element);
280→
281→  cleanupFns.push(() => {
282→    element.removeEventListener('keydown', handleKeyDown, { capture: true });
283→    attachedElements.delete(element);
284→  });
285→}
286→
287→/**
288→ * Find and attach to all input areas on the page
289→ */
290→function attachToAllInputs(): void {
291→  const editables = document.querySelectorAll<HTMLElement>(EDITABLE_SELECTORS);
292→  editables.forEach(attachToInput);
293→}
294→
295→// ============================================================================
296→// Observer Management
297→// ============================================================================
298→
299→/**
300→ * Setup observer to watch for dynamically added input elements
301→ * NOTE: Only call this when the feature is enabled!
302→ */
303→function setupObserver(): void {
304→  if (observer) return;
305→
306→  observer = new MutationObserver((mutations) => {
307→    for (const mutation of mutations) {
308→      for (const node of mutation.addedNodes) {
309→        if (!(node instanceof HTMLElement)) continue;
310→
311→        // Check if the node itself is an input
312→        if (
313→          node.isContentEditable ||
314→          node.getAttribute('role') === 'textbox' ||
315→          node.tagName === 'TEXTAREA'
316→        ) {
317→          attachToInput(node);
318→        }
319→
320→        // Check descendants
321→        const editables = node.querySelectorAll<HTMLElement>(EDITABLE_SELECTORS);
322→        editables.forEach(attachToInput);
323→      }
324→    }
325→  });
326→
327→  observer.observe(document.body, {
328→    childList: true,
329→    subtree: true,
330→  });
331→}
332→
333→/**
334→ * Disconnect the observer
335→ */
336→function disconnectObserver(): void {
337→  if (observer) {
338→    observer.disconnect();
339→    observer = null;
340→  }
341→}
342→
343→// ============================================================================
344→// Feature Enable/Disable
345→// ============================================================================
346→
347→/**
348→ * Enable the feature: attach listeners and start observing
349→ */
350→function enableFeature(): void {
351→  if (isEnabled) return;
352→
353→  isEnabled = true;
354→  attachToAllInputs();
355→  setupObserver();
356→
357→  console.log(LOG_PREFIX, 'Feature enabled');
358→}
359→
360→/**
361→ * Disable the feature: remove all listeners and stop observing
362→ */
363→function disableFeature(): void {
364→  if (!isEnabled) return;
365→
366→  isEnabled = false;
367→
368→  // Remove all event listeners
369→  cleanupFns.forEach((fn) => fn());
370→  cleanupFns = [];
371→
372→  // Stop observing DOM changes
373→  disconnectObserver();
374→
375→  console.log(LOG_PREFIX, 'Feature disabled');
376→}
