378→// ============================================================================
379→// Storage & Initialization
380→// ============================================================================
381→
382→/**
383→ * Load the enabled state from storage
384→ */
385→async function loadSettings(): Promise<boolean> {
386→  return new Promise((resolve) => {
387→    try {
388→      if (!chrome.storage?.sync?.get) {
389→        resolve(false);
390→        return;
391→      }
392→      chrome.storage.sync.get({ [StorageKeys.CTRL_ENTER_SEND]: false }, (result) => {
393→        const enabled = result?.[StorageKeys.CTRL_ENTER_SEND] === true;
394→        resolve(enabled);
395→      });
396→    } catch (error) {
397→      if (isExtensionContextInvalidatedError(error)) {
398→        resolve(false);
399→        return;
400→      }
401→      console.warn(LOG_PREFIX, 'Failed to load settings:', error);
402→      resolve(false);
403→    }
404→  });
405→}
406→
407→/**
408→ * Setup storage change listener
409→ * NOTE: This listener remains active even when feature is disabled,
410→ * so we can respond to setting changes.
411→ */
412→function setupStorageListener(): void {
413→  if (storageListener) return;
414→
415→  storageListener = (changes, areaName) => {
416→    if (areaName !== 'sync') return;
417→    if (!(StorageKeys.CTRL_ENTER_SEND in changes)) return;
418→
419→    const newValue = changes[StorageKeys.CTRL_ENTER_SEND].newValue === true;
420→
421→    if (newValue && !isEnabled) {
422→      enableFeature();
423→    } else if (!newValue && isEnabled) {
424→      disableFeature();
425→    }
426→  };
427→
428→  try {
429→    chrome.storage?.onChanged?.addListener(storageListener);
430→  } catch (error) {
431→    if (isExtensionContextInvalidatedError(error)) {
432→      return;
433→    }
434→    console.warn(LOG_PREFIX, 'Failed to setup storage listener:', error);
435→  }
436→}
437→
438→/**
439→ * Cleanup all resources
440→ */
441→function cleanup(): void {
442→  disableFeature();
443→
444→  if (storageListener) {
445→    try {
446→      chrome.storage?.onChanged?.removeListener(storageListener);
447→    } catch {
448→      // Ignore cleanup errors
449→    }
450→    storageListener = null;
451→  }
452→
453→  console.log(LOG_PREFIX, 'Cleanup complete');
454→}
455→
456→// ============================================================================
457→// Public API
458→// ============================================================================
459→
460→/**
461→ * Initialize the send behavior module
462→ * @returns A cleanup function to be called on unmount
463→ */
464→export async function startSendBehavior(): Promise<() => void> {
465→  // Always setup storage listener first (to respond to setting changes)
466→  setupStorageListener();
467→
468→  // Load initial setting and enable if needed
469→  const initialEnabled = await loadSettings();
470→  if (initialEnabled) {
471→    enableFeature();
472→  } else {
473→    console.log(LOG_PREFIX, 'Feature disabled, skipping initialization');
474→  }
475→
476→  return cleanup;
477→}
