  1→/**
  2→ * Adjusts the edit input textarea width based on user settings
  3→ * Targets the edit mode textarea in Gemini conversations
  4→ *
  5→ * Based on the chatWidth implementation pattern
  6→ */
  7→
  8→const STYLE_ID = 'gemini-voyager-edit-input-width';
  9→const DEFAULT_PERCENT = 60;
 10→const MIN_PERCENT = 30;
 11→const MAX_PERCENT = 100;
 12→const LEGACY_BASELINE_PX = 1200;
 13→
 14→const clampPercent = (value: number, min: number, max: number) =>
 15→  Math.min(max, Math.max(min, Math.round(value)));
 16→
 17→const normalizePercent = (value: number, fallback: number) => {
 18→  if (!Number.isFinite(value)) return fallback;
 19→  if (value > MAX_PERCENT) {
 20→    const approx = (value / LEGACY_BASELINE_PX) * 100;
 21→    return clampPercent(approx, MIN_PERCENT, MAX_PERCENT);
 22→  }
 23→  return clampPercent(value, MIN_PERCENT, MAX_PERCENT);
 24→};
