 26→/**
 27→ * Selectors for edit mode containers
 28→ * Based on actual DOM structure: .query-content.edit-mode
 29→ */
 30→function getEditModeSelectors(): string[] {
 31→  return ['.query-content.edit-mode', 'div.edit-mode', '[class*="edit-mode"]'];
 32→}
 33→
 34→/**
 35→ * Applies the specified width (%) to edit input elements
 36→ * Following the chatWidth pattern with container width removal and precise targeting
 37→ */
 38→function applyWidth(widthPercent: number): void {
 39→  const normalizedPercent = normalizePercent(widthPercent, DEFAULT_PERCENT);
 40→  const widthValue = `${normalizedPercent}vw`;
 41→
 42→  let style = document.getElementById(STYLE_ID) as HTMLStyleElement;
 43→  if (!style) {
 44→    style = document.createElement('style');
 45→    style.id = STYLE_ID;
 46→    document.head.appendChild(style);
 47→  }
 48→
 49→  const editModeSelectors = getEditModeSelectors();
 50→  const editModeRules = editModeSelectors.map((sel) => `${sel}`).join(',\n    ');
 51→
 52→  style.textContent = `
 53→    /* Remove width constraints from outer containers that contain edit mode (similar to chatWidth) */
 54→    .content-wrapper:has(.edit-mode),
 55→    .main-content:has(.edit-mode),
 56→    .content-container:has(.edit-mode) {
 57→      max-width: none !important;
 58→    }
 59→
 60→    /* Remove width constraints from main container when it has edit mode */
 61→    [role="main"]:has(.edit-mode) {
 62→      max-width: none !important;
 63→    }
 64→
 65→    main > div:has(.edit-mode) {
 66→      max-width: none !important;
 67→      width: 100% !important;
 68→    }
 69→
 70→    /* Target edit mode containers directly */
 71→    ${editModeRules} {
 72→      max-width: ${widthValue} !important;
 73→      width: min(100%, ${widthValue}) !important;
 74→    }
 75→
 76→    /* Target the edit-container within edit-mode */
 77→    .edit-mode .edit-container,
 78→    .query-content.edit-mode .edit-container {
 79→      max-width: ${widthValue} !important;
