 91→    /* Target text field wrapper and flex container */
 92→    .edit-mode .mat-mdc-text-field-wrapper,
 93→    .edit-mode .mat-mdc-form-field-flex,
 94→    .edit-mode .mdc-text-field {
 95→      max-width: ${widthValue} !important;
 96→      width: 100% !important;
 97→    }
