120→      margin-right: auto !important;
121→    }
122→
123→    input-container .input-area-container {
124→      max-width: 100% !important;
125→      width: 100% !important;
126→    }
127→
128→    input-area-v2 {
129→      max-width: 100% !important;
130→      width: 100% !important;
131→    }
