159→const ENABLED_KEY = 'gvEditInputWidthEnabled';
160→
161→/**
162→ * Initializes and starts the edit input width adjuster
163→ */
164→export function startEditInputWidthAdjuster(): void {
165→  let currentWidthPercent = DEFAULT_PERCENT;
166→  let enabled = false;
167→
168→  // Load initial state — request keys without defaults so we can distinguish
169→  // "key never existed" (upgrade) from "explicitly set to false"
170→  chrome.storage?.sync?.get(['geminiEditInputWidth', ENABLED_KEY], (res) => {
171→    const storedWidth = res?.geminiEditInputWidth;
172→    const normalized = normalizePercent(
173→      typeof storedWidth === 'number' ? storedWidth : DEFAULT_PERCENT,
174→      DEFAULT_PERCENT,
175→    );
176→    currentWidthPercent = normalized;
177→
178→    const enabledRaw = res?.[ENABLED_KEY];
179→    if (enabledRaw === undefined) {
180→      enabled =
181→        typeof storedWidth === 'number' &&
182→        normalizePercent(storedWidth, DEFAULT_PERCENT) !== DEFAULT_PERCENT;
183→      if (enabled) {
184→        try {
185→          chrome.storage?.sync?.set({ [ENABLED_KEY]: true });
186→        } catch {}
187→      }
188→    } else {
189→      enabled = enabledRaw === true;
190→    }
191→
192→    if (enabled) {
193→      applyWidth(currentWidthPercent);
194→    }
195→
196→    if (typeof storedWidth === 'number' && storedWidth !== normalized) {
197→      try {
198→        chrome.storage?.sync?.set({ geminiEditInputWidth: normalized });
199→      } catch (e) {
200→        console.warn('[Gemini Voyager] Failed to migrate edit input width to %:', e);
201→      }
202→    }
203→  });
204→
205→  // Listen for changes from storage (when user adjusts in popup)
206→  chrome.storage?.onChanged?.addListener((changes, area) => {
207→    if (area !== 'sync') return;
208→
209→    if (changes[ENABLED_KEY]) {
210→      enabled = changes[ENABLED_KEY].newValue === true;
211→      if (enabled) {
212→        applyWidth(currentWidthPercent);
213→      } else {
214→        removeStyles();
215→      }
216→    }
217→
218→    if (changes.geminiEditInputWidth) {
219→      const newWidth = changes.geminiEditInputWidth.newValue;
220→      if (typeof newWidth === 'number') {
221→        const normalized = normalizePercent(newWidth, DEFAULT_PERCENT);
222→        currentWidthPercent = normalized;
223→        if (enabled) {
224→          applyWidth(currentWidthPercent);
225→        }
226→
227→        if (normalized !== newWidth) {
228→          try {
229→            chrome.storage?.sync?.set({ geminiEditInputWidth: normalized });
230→          } catch (e) {
231→            console.warn('[Gemini Voyager] Failed to migrate edit input width to % on change:', e);
232→          }
233→        }
234→      }
235→    }
236→  });
237→
238→  // Re-apply styles when DOM changes (for dynamic content)
239→  // Use debouncing and cache the width to avoid storage reads
240→  let debounceTimer: number | null = null;
241→  const observer = new MutationObserver(() => {
242→    if (debounceTimer !== null) {
243→      clearTimeout(debounceTimer);
244→    }
245→    debounceTimer = window.setTimeout(() => {
246→      if (enabled) {
247→        applyWidth(currentWidthPercent);
248→      }
249→      debounceTimer = null;
250→    }, 200);
251→  });
252→
253→  // Observe the main conversation area for changes
254→  const main = document.querySelector('main');
255→  if (main) {
256→    observer.observe(main, {
257→      childList: true,
258→      subtree: true,
259→      attributes: true,
260→      attributeFilter: ['class'], // Watch for class changes (e.g., edit-mode added)
261→    });
262→  }
263→
264→  // Clean up on unload
265→  window.addEventListener('beforeunload', () => {
266→    observer.disconnect();
267→    removeStyles();
268→  });
269→}
