347→let observer: MutationObserver | null = null;
348→let initialized = false;
349→let eventController: AbortController | null = null;
350→let allowCollapseWhenNotEmpty = false; // Track the "collapse when not empty" setting
351→let collapseTimer: number | null = null; // Timer for delayed collapse
