252→function dedupeTags(tags: string[]): string[] {
253→  const seen = new Set<string>();
254→  const out: string[] = [];
255→  for (const raw of tags) {
256→    const t = raw.trim().toLowerCase();
257→    if (!t) continue;
258→    if (!seen.has(t)) {
259→      seen.add(t);
260→      out.push(t);
261→    }
262→  }
263→  return out;
264→}
