272→function copyText(text: string): Promise<void> {
273→  try {
274→    return navigator.clipboard.writeText(text);
275→  } catch {
276→    return new Promise<void>((resolve) => {
277→      const ta = document.createElement('textarea');
278→      ta.value = text;
279→      ta.style.position = 'fixed';
280→      ta.style.left = '-9999px';
281→      document.body.appendChild(ta);
282→      ta.select();
283→      try {
284→        document.execCommand('copy');
285→      } catch {}
286→      ta.remove();
287→      resolve();
288→    });
289→  }
290→}
