292→function computeAnchoredPosition(
293→  trigger: HTMLElement,
294→  panel: HTMLElement,
295→): { top: number; left: number } {
296→  const rect = trigger.getBoundingClientRect();
297→  const vw = window.innerWidth;
298→  const pad = 8;
299→  const panelW = Math.min(380, Math.max(300, panel.getBoundingClientRect().width || 320));
300→  const tentativeLeft = Math.min(vw - panelW - pad, Math.max(pad, rect.left + rect.width - panelW));
301→  const top = Math.max(pad, rect.top - (panel.getBoundingClientRect().height || 360) - 10);
302→  return { top, left: Math.round(tentativeLeft) };
303→}
