326→/**
327→ * Determine initialization delay based on tab visibility
328→ */
329→function getInitializationDelay(): number {
330→  // Check if tab is currently visible
331→  const isVisible = document.visibilityState === 'visible';
332→
333→  if (isVisible) {
334→    // Foreground tab: initialize immediately for good UX
335→    console.log('[Gemini Voyager] Foreground tab detected, initializing immediately');
336→    return 0;
337→  } else {
338→    // Background tab: add random delay to distribute load across multiple tabs
339→    const randomRange = BACKGROUND_TAB_MAX_DELAY - BACKGROUND_TAB_MIN_DELAY;
340→    const randomDelay = BACKGROUND_TAB_MIN_DELAY + Math.random() * randomRange;
341→    console.log(
342→      `[Gemini Voyager] Background tab detected, delaying initialization by ${Math.round(randomDelay)}ms`,
343→    );
344→    return randomDelay;
345→  }
346→}
347→
348→/**
349→ * Handle tab visibility changes
350→ */
351→function handleVisibilityChange(): void {
352→  if (document.visibilityState === 'visible' && !initialized) {
353→    // Tab became visible before initialization completed
354→    // Cancel any pending delayed initialization and start immediately
355→    if (initializationTimer !== null) {
356→      clearTimeout(initializationTimer);
357→      initializationTimer = null;
358→      console.log('[Gemini Voyager] Tab became visible, initializing immediately');
359→    }
360→    initializeFeatures();
361→  }
362→}
363→
364→// Main initialization logic
365→(function () {
366→  try {
367→    if (!hasValidExtensionContext()) return;
368→
369→    const onUnhandledRejection = (event: PromiseRejectionEvent) => {
370→      if (isExtensionContextInvalidatedError(event.reason)) {
371→        event.preventDefault();
372→      }
373→    };
374→    const onWindowError = (event: ErrorEvent) => {
375→      if (isExtensionContextInvalidatedError(event.error ?? event.message)) {
376→        event.preventDefault();
377→      }
378→    };
379→    window.addEventListener('unhandledrejection', onUnhandledRejection);
380→    window.addEventListener('error', onWindowError);
381→    const onStorageChanged = (
382→      changes: Record<string, chrome.storage.StorageChange>,
383→      areaName: string,
384→    ) => {
385→      if (
386→        (areaName !== 'sync' && areaName !== 'local') ||
387→        location.hostname !== 'gemini.google.com'
388→      ) {
389→        return;
390→      }
391→
392→      const forkSetting = changes[StorageKeys.FORK_ENABLED];
393→      if (!forkSetting) return;
394→
395→      const enabled = isForkFeatureEnabledValue(forkSetting.newValue);
396→      if (enabled) {
397→        if (!forkCleanup) {
398→          forkCleanup = startFork();
399→        }
400→      } else if (forkCleanup) {
401→        forkCleanup();
402→        forkCleanup = null;
403→      }
404→    };
405→
406→    // Quick check: only run on supported websites
407→    const hostname = location.hostname.toLowerCase();
408→    const isSupportedSite =
409→      hostname.includes('gemini.google.com') ||
410→      hostname.includes('business.gemini.google') ||
411→      hostname.includes('aistudio.google.com') ||
412→      hostname.includes('aistudio.google.cn');
413→
414→    // Initialize KaTeX configuration early to suppress Unicode warnings
415→    // This must run before any formulas are rendered on the page
416→    if (isSupportedSite) {
417→      initKaTeXConfig();
418→      // Initialize i18n early to ensure translations are available
419→      initI18n().catch((e) => console.error('[Gemini Voyager] i18n init error:', e));
420→    }
421→
422→    // If not a known site, check if it's a custom website (async)
423→    if (!isSupportedSite) {
424→      // For unknown sites, check storage asynchronously
425→      chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] }, (result) => {
426→        const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
427→          ? result.gvPromptCustomWebsites
428→          : [];
429→        const currentHost = hostname.replace(/^www\./, '');
430→
431→        const isCustomSite = customWebsites.some((website: string) => {
432→          const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
433→          return currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
434→        });
435→
436→        if (isCustomSite) {
437→          console.log('[Gemini Voyager] Custom website detected:', hostname);
438→          initializeFeatures();
439→        } else {
440→          // Not a supported site, exit early
441→          console.log('[Gemini Voyager] Not a supported website, skipping initialization');
442→        }
443→      });
444→      return;
445→    }
446→    chrome.storage?.onChanged?.addListener(onStorageChanged);
447→
448→    const delay = getInitializationDelay();
449→
450→    if (delay === 0) {
451→      // Immediate initialization for foreground tabs
452→      initializeFeatures();
453→    } else {
454→      // Delayed initialization for background tabs
455→      initializationTimer = window.setTimeout(() => {
456→        initializationTimer = null;
457→        initializeFeatures();
458→      }, delay);
459→    }
460→
461→    // Listen for visibility changes to handle tab switching
462→    document.addEventListener('visibilitychange', handleVisibilityChange);
463→
464→    // Setup cleanup on page unload to prevent memory leaks
465→    window.addEventListener('beforeunload', () => {
466→      try {
467→        window.removeEventListener('unhandledrejection', onUnhandledRejection);
468→        window.removeEventListener('error', onWindowError);
469→        if (folderManagerInstance) {
470→          folderManagerInstance.destroy();
471→          folderManagerInstance = null;
472→        }
473→        if (promptManagerInstance) {
474→          promptManagerInstance.destroy();
475→          promptManagerInstance = null;
476→        }
477→        if (quoteReplyCleanup) {
478→          quoteReplyCleanup();
479→          quoteReplyCleanup = null;
480→        }
481→        if (sendBehaviorCleanup) {
482→          sendBehaviorCleanup();
483→          sendBehaviorCleanup = null;
484→        }
485→        if (forkCleanup) {
486→          forkCleanup();
