  1→/**
  2→ * Send Behavior Module
  3→ *
  4→ * Modifies Gemini's input behavior:
  5→ * - Enter key inserts a newline instead of sending
  6→ * - Ctrl+Enter sends the message
  7→ *
  8→ * This feature is controlled by the `gvCtrlEnterSend` storage setting.
  9→ *
 10→ * ARCHITECTURE:
 11→ * - Observer and listeners are ONLY active when the feature is enabled
 12→ * - When disabled, no DOM observation or event handling occurs (zero performance overhead)
 13→ * - Storage listener remains active to respond to setting changes
 14→ */
 15→import { StorageKeys } from '@/core/types/common';
 16→import { isExtensionContextInvalidatedError } from '@/core/utils/extensionContext';
 17→
 18→import { getTextOffset, setCaretPosition } from './utils';
 19→
 20→// ============================================================================
 21→// Constants
 22→// ============================================================================
 23→
 24→/** Selectors for finding the send button */
 25→const SEND_BUTTON_SELECTORS = [
 26→  '.update-button', // Explicit class for Edit mode (User provided)
 27→  'button[aria-label*="Send"]',
 28→  'button[aria-label*="send"]',
 29→  'button[data-tooltip*="Send"]',
 30→  'button[data-tooltip*="send"]',
 31→  'button mat-icon[fonticon="send"]',
 32→  '[data-send-button]',
 33→  '.send-button',
 34→  // Fallback selectors
 35→  'button[aria-label*="Update"]',
 36→  'button[aria-label*="Save"]',
 37→  'button[aria-label*="更新"]',
 38→] as const;
 39→
 40→/** Selector for editable elements */
 41→const EDITABLE_SELECTORS = '[contenteditable="true"], [role="textbox"], textarea';
 42→
 43→/** Log prefix for consistent logging */
 44→const LOG_PREFIX = '[SendBehavior]';
 45→
 46→// ============================================================================
 47→// State
 48→// ============================================================================
 49→
 50→let isEnabled = false;
 51→let observer: MutationObserver | null = null;
 52→let cleanupFns: (() => void)[] = [];
 53→let storageListener:
 54→  | ((changes: Record<string, chrome.storage.StorageChange>, areaName: string) => void)
 55→  | null = null;
 56→
 57→/** Track elements that already have listeners attached to prevent duplicates */
 58→const attachedElements = new WeakSet<HTMLElement>();
 59→
 60→// ============================================================================
 61→// DOM Helpers
 62→// ============================================================================
 63→
 64→/**
 65→ * Find the send button associated with the current input element.
 66→ *
 67→ * Strategy:
 68→ * 1. Container Search: Use `closest()` to find a known container (e.g. `.text-input-field`, `chat-message`).
 69→ * 2. Scoped Button Search: Only search for buttons within the found container to avoid stale matches.
 70→ */
 71→function findSendButton(inputElement: HTMLElement): HTMLElement | null {
 72→  // 1. First, find a cohesive container wrapper that holds BOTH the input and its corresponding button
 73→  //    Gemini provides distinct containers for the main input and edit inputs
 74→  const containerSelectors = [
 75→    // Global/main chat input wrapper
 76→    '.text-input-field',
 77→    // Active conversation edit container
 78→    'chat-message',
 79→    'form',
 80→    // Modals/Dialogs
 81→    '[role="dialog"]',
 82→    '.mat-mdc-dialog-container',
 83→  ];
 84→
 85→  let container: HTMLElement | null = null;
 86→  for (const selector of containerSelectors) {
 87→    const closest = inputElement.closest(selector);
 88→    if (closest instanceof HTMLElement) {
 89→      container = closest;
 90→      break;
 91→    }
 92→  }
 93→
 94→  // 2. Search for the button strictly WITHIN the container or via bounded upward traversal
 95→  // If we found a known cohesive container, just search in it
 96→  if (container) {
 97→    for (const selector of SEND_BUTTON_SELECTORS) {
 98→      try {
 99→        const element = container.querySelector(selector);
100→        if (element instanceof HTMLElement) {
101→          const closestButton = element.closest('button');
102→          // Ensure the found button is still within our safe container boundary
103→          const button =
104→            closestButton && container.contains(closestButton) ? closestButton : element;
105→
106→          if (button instanceof HTMLElement && button.offsetParent !== null) {
107→            return button;
108→          }
109→        }
110→      } catch {
111→        // Invalid selector, continue
112→      }
113→    }
114→
115→    // Fallback search within container by icon text
116→    const allButtons = container.querySelectorAll('button');
117→    for (const button of allButtons) {
118→      const iconElement = button.querySelector('.material-symbols-outlined, mat-icon');
119→      if (
120→        iconElement?.textContent?.trim().toLowerCase() === 'send' &&
121→        button.offsetParent !== null
122→      ) {
123→        return button;
124→      }
125→    }
126→  }
127→
128→  return null;
129→}
130→
131→/**
132→ * Insert a newline in a contenteditable element
133→ *
134→ * Gemini uses Quill editor (identified by class "ql-editor").
135→ * Direct DOM manipulation with <br> elements doesn't work well with Quill
136→ * because it manages its own DOM state.
137→ *
138→ * Strategy:
139→ * 1. First try document.execCommand('insertLineBreak') - works in most browsers
140→ * 2. If that fails, simulate a Shift+Enter keypress which Quill handles natively
141→ */
142→function insertNewlineInContentEditable(target: HTMLElement): void {
143→  // Method 1: Try execCommand (deprecated but still works in most browsers)
144→  // This is the most reliable method for contenteditable elements
145→  // 1. SNAPSHOT: Remember where the cursor is (text offset)
146→  const currentOffset = getTextOffset(target);
147→
148→  // 2. EXECUTE: Native command
149→  // This might trigger a React re-render, creating a new DOM structure
150→  const success = document.execCommand('insertLineBreak', false);
151→
152→  if (success) {
153→    // 3. RESTORE: Put the cursor back where it belongs
154→    // Use requestAnimationFrame to wait for any immediate React re-renders to settle
155→    if (currentOffset !== null) {
156→      // +1 to account for the newly inserted newline character
157→      const newOffset = currentOffset + 1;
158→
159→      // Try immediate restore (for synchronous DOM updates)
160→      setCaretPosition(target, newOffset);
161→
162→      // Also try next frame (for asynchronous React updates)
163→      requestAnimationFrame(() => {
164→        setCaretPosition(target, newOffset);
165→      });
166→    }
167→
168→    // Trigger input event to notify listeners (ensure data sync)
169→    // NOTE: Maintainer's code had this. We kept it but manage the cursor consequence.
170→    target.dispatchEvent(new Event('input', { bubbles: true }));
171→    return;
172→  }
173→  // Method 2: Try insertHTML with a <br> tag
174→  const htmlSuccess = document.execCommand('insertHTML', false, '<br><br>');
175→
176→  if (htmlSuccess) {
177→    target.dispatchEvent(new Event('input', { bubbles: true }));
178→    return;
179→  }
180→
181→  // Method 3: Simulate Shift+Enter keypress as fallback
182→  // This tells Quill to handle the newline in its own way
183→  const shiftEnterEvent = new KeyboardEvent('keydown', {
184→    key: 'Enter',
185→    code: 'Enter',
186→    keyCode: 13,
187→    which: 13,
188→    shiftKey: true,
189→    bubbles: true,
190→    cancelable: true,
191→  });
192→
193→  target.dispatchEvent(shiftEnterEvent);
194→}
195→
196→/**
197→ * Insert a newline in a textarea
198→ */
199→function insertNewlineInTextarea(textarea: HTMLTextAreaElement): void {
200→  const start = textarea.selectionStart;
201→  const end = textarea.selectionEnd;
202→  const value = textarea.value;
203→
204→  textarea.value = value.substring(0, start) + '\n' + value.substring(end);
205→  textarea.selectionStart = textarea.selectionEnd = start + 1;
206→
207→  // Trigger input event to notify any listeners
208→  textarea.dispatchEvent(new Event('input', { bubbles: true }));
209→}
210→
211→// ============================================================================
212→// Event Handlers
213→// ============================================================================
214→
215→/**
216→ * Handle keydown events on the input area
217→ */
218→function handleKeyDown(event: KeyboardEvent): void {
219→  // Early exit if feature is disabled (should not happen, but defensive check)
220→  if (!isEnabled) return;
