            !dmgUrl &&
            typeof cachedEntry === 'object' &&
            cachedEntry !== null &&
            'fetchedAt' in cachedEntry &&
            typeof (cachedEntry as Record<string, unknown>).fetchedAt === 'number' &&
            now - ((cachedEntry as Record<string, unknown>).fetchedAt as number) >=
