content.content:
  1→import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
  2→
  3→const STYLE_ID = 'gemini-voyager-chat-width';
  4→const STORAGE_KEY = 'geminiChatWidth';
  5→const MOCK_SCREEN_WIDTH = 1920;
  6→
  7→type StorageChangeListener = (
  8→  changes: Record<string, chrome.storage.StorageChange>,
  9→  area: string,
 10→) => void;
 11→
 12→function getInjectedStyle(): HTMLStyleElement {
 13→  const style = document.getElementById(STYLE_ID);
 14→  expect(style).not.toBeNull();
 15→  return style as HTMLStyleElement;
 16→}
 17→
 18→function percentToPixels(percent: number): number {
 19→  return Math.round((percent / 100) * MOCK_SCREEN_WIDTH);
 20→}
 21→
 22→function expectTableRuleWidth(styleText: string, percent: number): void {
 23→  const px = percentToPixels(percent);
 24→  const escapedWidth = px.toString();
 25→  const tableRulePattern = new RegExp(
 26→    String.raw`\/\* Gemini table containers \*\/[\s\S]*table-block,[\s\S]*\.table-block,[\s\S]*\.table-block \.table-content[\s\S]*\{[\s\S]*max-width: ${escapedWidth}px !important;[\s\S]*width: min\(100%, ${escapedWidth}px\) !important;`,
 27→  );
 28→  expect(styleText).toMatch(tableRulePattern);
 29→}
 30→
 31→function expectSingleTableScrollbarRules(styleText: string): void {
 32→  expect(styleText).toContain('.table-block.has-scrollbar');
 33→  expect(styleText).toContain('.table-block.new-table-style');
 34→  expect(styleText).toContain('overflow-x: hidden !important;');
 35→  expect(styleText).toContain('.table-block .table-content');
 36→  expect(styleText).toContain('overflow-x: auto !important;');
 37→}
 38→
 39→describe('chatWidth', () => {
 40→  let storageChangeListeners: StorageChangeListener[];
 41→
 42→  beforeEach(() => {
 43→    vi.resetModules();
 44→    vi.clearAllMocks();
 45→
 46→    document.head.innerHTML = '';
 47→    document.body.innerHTML = '<main></main>';
 48→
 49→    // Mock screen dimensions for deterministic tests
 50→    Object.defineProperty(window, 'screen', {
 51→      value: { availWidth: MOCK_SCREEN_WIDTH, width: MOCK_SCREEN_WIDTH },
 52→      writable: true,
 53→      configurable: true,
 54→    });
 55→
 56→    storageChangeListeners = [];
 57→
 58→    (chrome.storage.sync.get as unknown as ReturnType<typeof vi.fn>).mockImplementation(
 59→      (_defaults: Record<string, unknown>, callback: (value: Record<string, unknown>) => void) => {
 60→        callback({ [STORAGE_KEY]: 85, gvChatWidthEnabled: true });
 61→      },
 62→    );
 63→
 64→    (
 65→      chrome.storage.onChanged.addListener as unknown as ReturnType<typeof vi.fn>
 66→    ).mockImplementation((listener: StorageChangeListener) => {
 67→      storageChangeListeners.push(listener);
 68→    });
 69→  });
 70→
 71→  afterEach(() => {
 72→    window.dispatchEvent(new Event('beforeunload'));
 73→  });
 74→
 75→  it('applies widescreen rules to Gemini table blocks', async () => {
 76→    const { startChatWidthAdjuster } = await import('../index');
 77→    startChatWidthAdjuster();
 78→
 79→    const styleText = getInjectedStyle().textContent ?? '';
 80→
 81→    expectTableRuleWidth(styleText, 85);
 82→    expect(styleText).toContain('table-block .table-block');
 83→    expect(styleText).toContain('.table-block.has-scrollbar');
 84→    expect(styleText).toContain('.table-block.new-table-style');
 85→    expect(styleText).toContain('.table-block .table-content');
 86→    expect(styleText).toContain('.table-block-component');
 87→    expect(styleText).toContain('.horizontal-scroll-wrapper');
 88→    expectSingleTableScrollbarRules(styleText);
 89→  });
 90→
 91→  it('updates table widescreen rules when width setting changes', async () => {
 92→    const { startChatWidthAdjuster } = await import('../index');
 93→    startChatWidthAdjuster();
 94→
 95→    expect(storageChangeListeners.length).toBeGreaterThan(0);
 96→
 97→    storageChangeListeners[0]({ [STORAGE_KEY]: { oldValue: 85, newValue: 92 } }, 'sync');
 98→
 99→    const styleText = getInjectedStyle().textContent ?? '';
100→    expectTableRuleWidth(styleText, 92);
101→    expect(styleText).toContain('table-block .table-content');
102→    expectSingleTableScrollbarRules(styleText);
103→  });
104→
105→  it('adapts width for narrow viewports (split-screen behavior)', async () => {
106→    // Simulate: user sets 70% on a 1920px screen → 1344px max-width
107→    // In split-screen (960px viewport), min(100%, 1344px) fills the viewport
108→    (chrome.storage.sync.get as unknown as ReturnType<typeof vi.fn>).mockImplementation(
109→      (_defaults: Record<string, unknown>, callback: (value: Record<string, unknown>) => void) => {
110→        callback({ [STORAGE_KEY]: 70, gvChatWidthEnabled: true });
111→      },
